import { NextResponse } from 'next/server'; import { prisma } from '@/lib/db'; import { setSession, verifyPassword } from '@/lib/auth';
export async function POST(req:Request){ const form=await req.formData(); const email=String(form.get('email')); const password=String(form.get('password')); const user=await prisma.user.findUnique({where:{email}}); if(!user || !(await verifyPassword(password,user.passwordHash))) return NextResponse.redirect(new URL('/login?error=1',req.url)); await setSession(user.id); return NextResponse.redirect(new URL('/dashboard',req.url)); }
